+    static int branchToExceptionBoundary(boolean b) {
+        int result = 0;
+        try (Closeable _ = () -> {}) {
+            for (Object _ : List.of(new Object())) {
+                try (Closeable _ = () -> {}) {
+                    result++;
+                } catch (IOException _) {
+                    throw new RuntimeException();
+                }
+            }
+        } catch (IOException _) {
+            throw new RuntimeException();
+        }
+        return b ? result : -result;
+    }
